import json, os
p='/root/.openclaw/workspace/webhook/queue/pending.json'
if not os.path.exists(p):
    print('NO_FILE')
else:
    try:
        with open(p,'r',encoding='utf-8') as f:
            data=json.load(f)
    except Exception as e:
        print('ERROR',e)
    else:
        if isinstance(data,list):
            print('LIST',len(data))
            if data:
                print(json.dumps(data,ensure_ascii=False))
        elif isinstance(data,dict):
            # common wrappers
            items=None
            for k in ('pending','items','notifications','events','queue'):
                if isinstance(data.get(k),list):
                    items=data[k]; break
            if items is None:
                # maybe empty object or single event
                print('DICT_KEYS',','.join(data.keys()))
                if data:
                    print(json.dumps(data,ensure_ascii=False))
            else:
                print('WRAPPED',len(items),k)
                if items:
                    print(json.dumps(items,ensure_ascii=False))
        else:
            print('TYPE',type(data).__name__)
            print(json.dumps(data,ensure_ascii=False))
